before_code:
module shift_unit(
  input [31:0] data_in,
  input [4:0] shift_amt,
  output [31:0] shifted_data
);
  assign shifted_data = data_in << shift_amt;
endmodule

module processor(
  input [31:0] operand,
  input [4:0] amount,
  output [31:0] result
);
  shift_unit shifter (
    .data_in(operand[15:0]),
    .shift_amt(amount),
    .shifted_data(result)
  );
endmodule

after_code:
module shift_unit(
  input [31:0] data_in,
  input [4:0] shift_amt,
  output [31:0] shifted_data
);
  assign shifted_data = data_in << shift_amt;
endmodule

module processor(
  input [31:0] operand,
  input [4:0] amount,
  output [31:0] result
);
  shift_unit shifter (
    .data_in(operand[31:0]),
    .shift_amt(amount),
    .shifted_data(result)
  );
endmodule
